#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=5010;int dp[N][N],h[N],n,ans;
inline double Cnt(const int &i,const int &j){return 1.0*(h[i]-h[j])/(i-j);}
int main()
{
	n=read();rep(1,n,i)h[i]=read(),dp[i][i]=1;
	rep(1,n,r)
	{
		int s=1,k=0;ans^=1;drep(r-1,1,l)
		{
			if(!k||Cnt(l,r)<Cnt(k,r)){s+=min(dp[l+1][k-1],dp[l+1][k]);k=l;}
			ans^=(dp[l][r]=s+min(dp[l][k],dp[l][k-1]));
		}
	}
	printf("%d\n",ans);return 0;
}
